import 'dart:developer' as developer;
import 'package:flutter/foundation.dart';

/// Environment-aware log levels
enum LogLevel {
  debug(0),
  info(1),
  warning(2),
  error(3),
  none(4);

  const LogLevel(this.value);
  final int value;
}

/// Production-safe logging system that redacts sensitive data.
///
/// SECURITY: This logger is designed to NEVER log passwords, tokens,
/// credentials, or sensitive personal data. Verbose logging is restricted
/// to debug builds only.
class SecureLogger {
  static SecureLogger? _instance;
  static SecureLogger get instance => _instance ??= SecureLogger._();

  SecureLogger._();

  /// In production, only warnings and errors are logged.
  /// In debug/profile, info and above are logged.
  LogLevel get _minimumLevel {
    if (kReleaseMode) return LogLevel.warning;
    if (kProfileMode) return LogLevel.info;
    return LogLevel.debug; // only in true debug builds
  }

  /// Fields that must NEVER appear in logs
  static const _sensitiveKeys = {
    'password',
    'passwd',
    'secret',
    'token',
    'access_token',
    'refresh_token',
    'id_token',
    'authorization',
    'cookie',
    'set-cookie',
    'api_key',
    'apikey',
    'api-key',
    'credit_card',
    'card_number',
    'cvv',
    'ssn',
    'social_security',
    'pin',
    'otp',
    'mfa_code',
    'private_key',
    'client_secret',
  };

  /// Headers that must be redacted
  static const _sensitiveHeaders = {
    'authorization',
    'cookie',
    'set-cookie',
    'x-api-key',
    'x-auth-token',
    'proxy-authorization',
  };

  void _log(LogLevel level, String category, String message,
      {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) {
    if (level.value < _minimumLevel.value) return;

    final sanitizedMetadata = metadata != null ? _redactMap(metadata) : null;
    final timestamp = DateTime.now().toUtc().toIso8601String();
    final logEntry = StringBuffer()
      ..write('[$timestamp] ')
      ..write('[${level.name.toUpperCase()}] ')
      ..write('[$category] ')
      ..write(message);

    if (sanitizedMetadata != null && sanitizedMetadata.isNotEmpty) {
      logEntry.write(' | metadata: $sanitizedMetadata');
    }

    if (error != null) {
      // SECURITY: In production, do not expose full error details or stack traces.
      if (kReleaseMode) {
        logEntry.write(' | error: ${_sanitizeErrorMessage(error.toString())}');
        // Stack traces are intentionally omitted in production logs
      } else {
        logEntry.write(' | error: $error');
        if (stackTrace != null) {
          logEntry.write('\n$stackTrace');
        }
      }
    }

    final logString = logEntry.toString();

    // Use developer.log in debug, debugPrint for profile, print avoided in release
    if (kDebugMode) {
      developer.log(
        logString,
        name: category,
        level: level.value * 250, // map to dart:developer levels
        error: error,
        stackTrace: stackTrace,
      );
    } else if (!kReleaseMode) {
      debugPrint(logString);
    } else {
      // In release mode, send to your secure logging backend instead of printing.
      // NEVER use print() in production — it can leak to device logs.
      _sendToSecureBackend(level, category, message, sanitizedMetadata);
    }
  }

  /// Recursively redact sensitive fields from a map
  Map<String, dynamic> _redactMap(Map<String, dynamic> data) {
    final result = <String, dynamic>{};
    for (final entry in data.entries) {
      final keyLower = entry.key.toLowerCase();
      if (_sensitiveKeys.any((k) => keyLower.contains(k))) {
        result[entry.key] = '[REDACTED]';
      } else if (entry.value is Map<String, dynamic>) {
        result[entry.key] = _redactMap(entry.value as Map<String, dynamic>);
      } else if (entry.value is List) {
        result[entry.key] = _redactList(entry.value as List);
      } else if (entry.value is String &&
          _looksLikeSensitiveValue(entry.value as String)) {
        result[entry.key] = '[REDACTED]';
      } else {
        result[entry.key] = entry.value;
      }
    }
    return result;
  }

  List<dynamic> _redactList(List<dynamic> list) {
    return list.map((item) {
      if (item is Map<String, dynamic>) return _redactMap(item);
      if (item is List) return _redactList(item);
      return item;
    }).toList();
  }

  /// Heuristic: detect values that look like tokens, keys, or encoded credentials
  bool _looksLikeSensitiveValue(String value) {
    if (value.startsWith('Bearer ')) return true;
    if (value.startsWith('Basic ')) return true;
    if (value.startsWith('eyJ')) return true; // JWT
    // Long base64-like strings are suspicious
    if (value.length > 40 && RegExp(r'^[A-Za-z0-9+/=_\-]+$').hasMatch(value)) {
      return true;
    }
    return false;
  }

  /// Redact headers, preserving only safe ones
  Map<String, String> _redactHeaders(Map<String, String> headers) {
    final result = <String, String>{};
    for (final entry in headers.entries) {
      if (_sensitiveHeaders.contains(entry.key.toLowerCase())) {
        result[entry.key] = '[REDACTED]';
      } else if (_looksLikeSensitiveValue(entry.value)) {
        result[entry.key] = '[REDACTED]';
      } else {
        result[entry.key] = entry.value;
      }
    }
    return result;
  }

  /// Remove internal system details from error messages shown in production
  String _sanitizeErrorMessage(String message) {
    // Remove file paths
    message = message.replaceAll(RegExp(r'/[^\s]+\.dart:\d+:\d+'), '[internal]');
    // Remove SQL or query fragments
    message = message.replaceAll(
        RegExp(r'(SELECT|INSERT|UPDATE|DELETE|DROP|CREATE)\s+.*',
            caseSensitive: false),
        '[query redacted]');
    // Remove connection strings
    message = message.replaceAll(
        RegExp(r'(postgres|mysql|mongodb|redis)://[^\s]+'), '[connection redacted]');
    // Truncate overly long messages
    if (message.length > 200) {
      message = '${message.substring(0, 200)}... [truncated]';
    }
    return message;
  }

  /// Placeholder for production logging backend (e.g., Sentry, Datadog, CloudWatch)
  void _sendToSecureBackend(LogLevel level, String category, String message,
      Map<String, dynamic>? metadata) {
    // TODO: Integrate with your secure, access-controlled logging service.
    // Ensure the backend:
    // - Encrypts logs in transit and at rest
    // - Has role-based access control
    // - Retains logs per your data retention policy
    // - Is NOT accessible from client devices
  }

  // ─── Public API ───────────────────────────────────────────────────────

  void debug(String category, String message, {Map<String, dynamic>? metadata}) {
    _log(LogLevel.debug, category, message, metadata: metadata);
  }

  void info(String category, String message, {Map<String, dynamic>? metadata}) {
    _log(LogLevel.info, category, message, metadata: metadata);
  }

  void warning(String category, String message,
      {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) {
    _log(LogLevel.warning, category, message,
        metadata: metadata, error: error, stackTrace: stackTrace);
  }

  void logError(String category, String message,
      {Map<String, dynamic>? metadata, Object? error, StackTrace? stackTrace}) {
    _log(LogLevel.error, category, message,
        metadata: metadata, error: error, stackTrace: stackTrace);
  }

  // ─── HTTP Logging ────────────────────────────────────────────────────

  /// Log an outgoing HTTP request. Sensitive headers and body fields are redacted.
  void logHttpRequest({
    required String method,
    required String url,
    Map<String, String>? headers,
    Map<String, dynamic>? body,
    Map<String, dynamic>? queryParameters,
  }) {
    // SECURITY: Strip query params that might contain tokens
    final sanitizedUrl = _redactUrlParams(url);

    final metadata = <String, dynamic>{
      'method': method,
      'url': sanitizedUrl,
    };

    if (headers != null) {
      metadata['headers'] = _redactHeaders(headers);
    }

    if (body != null) {
      // SECURITY: Only log body structure in debug mode, redact sensitive fields always
      if (kDebugMode) {
        metadata['body'] = _redactMap(body);
      } else {
        metadata['body_keys'] = body.keys.toList(); // structure only, no values
      }
    }

    if (queryParameters != null) {
      metadata['query'] = _redactMap(queryParameters);
    }

    info('HTTP', 'Request: $method $sanitizedUrl', metadata: metadata);
  }

  /// Log an HTTP response. Body content is summarized, not dumped.
  void logHttpResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, String>? headers,
    dynamic body,
    Duration? duration,
  }) {
    final sanitizedUrl = _redactUrlParams(url);
    final metadata = <String, dynamic>{
      'method': method,
      'url': sanitizedUrl,
      'status_code': statusCode,
    };

    if (duration != null) {
      metadata['duration_ms'] = duration.inMilliseconds;
    }

    if (headers != null) {
      metadata['response_headers'] = _redactHeaders(headers);
    }

    // SECURITY: Never log full response bodies in production.
    // They may contain user PII, tokens, or sensitive data.
    if (body != null) {
      if (body is Map<String, dynamic>) {
        if (kDebugMode) {
          metadata['response_body'] = _redactMap(body);
        } else {
          metadata['response_body_keys'] = body.keys.toList();
        }
      } else if (body is String) {
        metadata['response_body_length'] = body.length;
        // Do NOT log the string content
      }
    }

    final level = statusCode >= 500
        ? LogLevel.error
        : statusCode >= 400
            ? LogLevel.warning
            : LogLevel.info;

    _log(level, 'HTTP', 'Response: $statusCode $method $sanitizedUrl',
        metadata: metadata);
  }

  String _redactUrlParams(String url) {
    try {
      final uri = Uri.parse(url);
      if (uri.queryParameters.isEmpty) return url;

      final redactedParams = <String, String>{};
      for (final entry in uri.queryParameters.entries) {
        final keyLower = entry.key.toLowerCase();
        if (_sensitiveKeys.any((k) => keyLower.contains(k)) ||
            _looksLikeSensitiveValue(entry.value)) {
          redactedParams[entry.key] = '[REDACTED]';
        } else {
          redactedParams[entry.key] = entry.value;
        }
      }
      return uri.replace(queryParameters: redactedParams).toString();
    } catch (_) {
      return url;
    }
  }

  // ─── Database Operation Logging ──────────────────────────────────────

  /// Log a database operation. Query details are only shown in debug builds.
  void logDatabaseOperation({
    required String operation, // e.g., 'read', 'write', 'delete'
    required String table,
    int? rowCount,
    Duration? duration,
    String? query, // Only logged in debug mode
    Map<String, dynamic>? parameters,
    Object? error,
    StackTrace? stackTrace,
  }) {
    final metadata = <String, dynamic>{
      'operation': operation,
      'table': table,
    };

    if (rowCount != null) metadata['row_count'] = rowCount;
    if (duration != null) metadata['duration_ms'] = duration.inMilliseconds;

    // SECURITY: Never log raw queries or parameters in production.
    // They may reveal schema details or contain user data.
    if (kDebugMode) {
      if (query != null) metadata['query'] = query;
      if (parameters != null) metadata['parameters'] = _redactMap(parameters);
    }

    if (error != null) {
      logError('DATABASE', 'Operation failed: $operation on $table',
          metadata: metadata, error: error, stackTrace: stackTrace);
    } else {
      debug('DATABASE', 'Operation: $operation on $table', metadata: metadata);
    }
  }

  // ─── Authentication Flow Logging ─────────────────────────────────────

  /// Log authentication events WITHOUT any credentials or tokens.
  void logAuthEvent({
    required String event, // e.g., 'login_attempt', 'login_success', 'logout', 'token_refresh'
    String? userId, // Use opaque ID, never email/phone in production
    String? method, // e.g., 'email', 'google', 'biometric'
    bool? success,
    String? failureReason, // Generic reason, no internal details
    Map<String, dynamic>? additionalData,
  }) {
    final metadata = <String, dynamic>{
      'event': event,
    };

    if (method != null) metadata['method'] = method;
    if (success != null) metadata['success'] = success;

    // SECURITY: In production, use anonymized/opaque user IDs only
    if (userId != null) {
      if (kReleaseMode) {
        // Only include a truncated/hashed version
        metadata['user_id_hint'] = _anonymizeId(userId);
      } else {
        metadata['user_id'] = userId;
      }
    }

    if (failureReason != null) {
      // SECURITY: Use generic failure reasons, never expose internal auth details
      metadata['failure_reason'] = _sanitizeAuthFailureReason(failureReason);
    }

    if (additionalData != null) {
      metadata.addAll(_redactMap(additionalData));
    }

    // SECURITY: NEVER log these, even in debug:
    // - Passwords or password hashes
    // - Auth tokens (access, refresh, ID tokens)
    // - MFA codes or recovery codes
    // - Session identifiers

    final level = (success == false) ? LogLevel.warning : LogLevel.info;
    _log(level, 'AUTH', 'Auth event: $event', metadata: metadata);
  }

  String _anonymizeId(String id) {
    if (id.length <= 4) return '****';
    return '${id.substring(0, 2)}***${id.substring(id.length - 2)}';
  }

  String _sanitizeAuthFailureReason(String reason) {
    // Map internal errors to generic messages
    final reasonLower = reason.toLowerCase();
    if (reasonLower.contains('password')) return 'invalid_credentials';
    if (reasonLower.contains('not found')) return 'invalid_credentials';
    if (reasonLower.contains('expired')) return 'session_expired';
    if (reasonLower.contains('locked')) return 'account_locked';
    if (reasonLower.contains('rate') || reasonLower.contains('throttl')) {
      return 'rate_limited';
    }
    if (kReleaseMode) return 'auth_failure'; // generic in production
    return reason; // more detail in debug
  }

  // ─── User Interaction Logging ────────────────────────────────────────

  /// Log user interactions for analytics/debugging. No PII.
  void logUserInteraction({
    required String action, // e.g., 'button_tap', 'screen_view', 'form_submit'
    required String target, // e.g., 'login_button', 'settings_screen'
    Map<String, dynamic>? properties,
  }) {
    final metadata = <String, dynamic>{
      'action': action,
      'target': target,
    };

    if (properties != null) {
      // SECURITY: Redact any sensitive data that might be in interaction properties
      metadata.addAll(_redactMap(properties));
    }

    debug('UI', 'Interaction: $action on $target', metadata: metadata);
  }

  // ─── App Health / Performance ────────────────────────────────────────

  void logPerformance({
    required String operation,
    required Duration duration,
    Map<String, dynamic>? metadata,
  }) {
    final data = <String, dynamic>{
      'operation': operation,
      'duration_ms': duration.inMilliseconds,
      ...?metadata != null ? _redactMap(metadata) : null,
    };

    // Warn if operations are slow
    final level = duration.inMilliseconds > 3000
        ? LogLevel.warning
        : LogLevel.debug;

    _log(level, 'PERF', 'Performance: $operation took ${duration.inMilliseconds}ms',
        metadata: data);
  }

  void logAppLifecycle(String event, {Map<String, dynamic>? metadata}) {
    info('LIFECYCLE', event, metadata: metadata);
  }
}


// ─── HTTP Interceptor Example (for use with dio or http) ─────────────

// lib/logging/logging_http_interceptor.dart

/// Example interceptor that uses SecureLogger for all HTTP traffic.
/// Adapt to your HTTP client (dio, http, chopper, etc.)
class LoggingHttpInterceptor {
  final SecureLogger _logger = SecureLogger.instance;

  void onRequest({
    required String method,
    required String url,
    Map<String, String>? headers,
    Map<String, dynamic>? body,
  }) {
    _logger.logHttpRequest(
      method: method,
      url: url,
      headers: headers,
      body: body,
    );
  }

  void onResponse({
    required String method,
    required String url,
    required int statusCode,
    Map<String, String>? headers,
    dynamic body,
    Duration? duration,
  }) {
    _logger.logHttpResponse(
      method: method,
      url: url,
      statusCode: statusCode,
      headers: headers,
      body: body,
      duration: duration,
    );
  }

  void onError({
    required String method,
    required String url,
    int? statusCode,
    Object? error,
    StackTrace? stackTrace,
    Duration? duration,
  }) {
    _logger.logError(
      'HTTP',
      'Request failed: $method ${Uri.parse(url).path}',
      metadata: {
        'method': method,
        'status_code': statusCode ?? 0,
        if (duration != null) 'duration_ms': duration.inMilliseconds,
      },
      error: error,
      stackTrace: stackTrace,
    );
  }
}


