// lib/main.dart (example usage)

void exampleUsage() {
  final logger = SecureLogger.instance;

  // ✅ SECURE: Auth logging without credentials
  logger.logAuthEvent(
    event: 'login_attempt',
    method: 'email',
    // NEVER pass password or token here
  );

  logger.logAuthEvent(
    event: 'login_success',
    userId: 'usr_abc123def456',
    method: 'email',
    success: true,
  );

  logger.logAuthEvent(
    event: 'login_failure',
    method: 'email',
    success: false,
    failureReason: 'invalid_credentials', // generic, not "password mismatch for user X"
  );

  // ✅ SECURE: HTTP logging with automatic redaction
  logger.logHttpRequest(
    method: 'POST',
    url: 'https://api.example.com/auth/login',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer eyJhbGciOi...', // Will be redacted automatically
    },
    body: {
      'email': 'user@example.com',
      'password': 'supersecret123', // Will be redacted automatically
    },
  );

  logger.logHttpResponse(
    method: 'POST',
    url: 'https://api.example.com/auth/login',
    statusCode: 200,
    body: {
      'user_id': 'usr_123',
      'access_token': 'eyJhbGciOi...', // Will be redacted automatically
      'refresh_token': 'dGhpcyBpcyBh...', // Will be redacted automatically
      'expires_in': 3600,
    },
    duration: const Duration(milliseconds: 245),
  );

  // ✅ SECURE: Database logging without query details in production
  logger.logDatabaseOperation(
    operation: 'read',
    table: 'user_profiles',
    rowCount: 1,
    duration: const Duration(milliseconds: 12),
  );

  // ✅ SECURE: User interaction logging
  logger.logUserInteraction(
    action: 'screen_view',
    target: 'profile_screen',
    properties: {'source': 'navigation_drawer'},
  );

  // ✅ SECURE: Performance monitoring
  logger.logPerformance(
    operation: 'image_upload',
    duration: const Duration(milliseconds: 1500),
    metadata: {'file_size_kb': 2048},
  );

  // ✅ SECURE: App lifecycle
  logger.logAppLifecycle('app_resumed');

  // ❌ INSECURE — NEVER DO THIS:
  // print('User password: $password');
  // print('Token: $accessToken');
  // debugPrint('Full response: ${response.body}');
  // print('SQL: SELECT * FROM users WHERE email = "$email"');
  // logger.debug('AUTH', 'Password hash: $hash');
}